    val searchTabs = setOf("media", "downloads", "links", "files", "music", "voice")
    var hasGlobalSearchAnchor = false
    var hasChannelsAnchor = false
    var tabMatchCount = 0
    val screenContent = mutableListOf<String>()

    fun extract(node: AccessibilityNodeInfo?) {
        if (node == null) return
        val txt = node.text?.toString()?.lowercase() ?: ""
        val desc = node.contentDescription?.toString()?.lowercase() ?: ""

        if (txt == "global search" || desc == "global search") hasGlobalSearchAnchor = true
        if (txt == "channels" || desc == "channels") hasChannelsAnchor = true
        if (searchTabs.contains(txt) || searchTabs.contains(desc)) tabMatchCount++

        if (!node.text.isNullOrBlank()) screenContent.add(node.text.toString())
        for (i in 0 until node.childCount) extract(node.getChild(i))
    }
