                    val isUrlBar = node.isEditable || resId.contains("url") || resId.contains("address") || resId.contains("omnibox")
                    // Also check web content description as browsers often put URL there
                    val isWebContent = node.className == "android.webkit.WebView" || resId.contains("content")
                    if (!isUrlBar && isWebContent) continue

                    val rawText = (node.text?.toString() ?: "") + " " + (node.contentDescription?.toString() ?: "")
                    val lowerText = rawText.lowercase()
                    val index = lowerText.indexOf(site)

                    if (index != -1) {
                        val charBefore = if (index > 0) lowerText[index - 1] else ' '
                        if (!charBefore.isLetterOrDigit()) {
                            DebugLogger.log("BROWSER_KILL", "Site: $site | Full: $rawText")

                            val targetPkg = root.packageName?.toString() ?: activePackage
                            if (LockManager.isNonStandardApp(applicationContext, targetPkg)) {
                                LockManager.banNonStandardApp(applicationContext)
                                showInstantOverlay("ROGUE_VIOLATION")
                            } else {
                                handleBrowserStrike()
                            }
                            return
                        }
                    }
                }
            }

            // 2. CONTENT SCANNING (Hidden WebViews)
            val screenContent = StringBuilder()
            fun extractBrowser(node: AccessibilityNodeInfo?) {
                if (node == null) return
                if (!node.text.isNullOrBlank()) screenContent.append(node.text).append(" ")
                if (!node.contentDescription.isNullOrBlank()) screenContent.append(node.contentDescription).append(" ")
                for (i in 0 until node.childCount) extractBrowser(node.getChild(i))
            }
            extractBrowser(root)
            val fullPageText = screenContent.toString()
            if (!WordBank.isSafe(applicationContext, fullPageText)) {
