function jumpToElement(element, tabId, navIndex) {
    console.group(`[JumpEngine] Target Tab: ${tabId}`);
    if (!element) {
        console.error("[JumpEngine] Aborted: Element reference is null.");
        console.groupEnd();
        return;
    }

    console.log("[JumpEngine] Switching Tab...");
    switchTab(tabId, document.querySelectorAll('.nav-item')[navIndex]);

    // Increase delay and use a retry loop for scrolling
    let attempts = 0;
    const maxAttempts = 5;

    const performScroll = () => {
        attempts++;
        const rect = element.getBoundingClientRect();
        const isVisible = rect.top !== 0 || rect.left !== 0;

        console.log(`[JumpEngine] Scroll Attempt ${attempts}. Visible in DOM: ${isVisible}`);

        if (isVisible) {
            element.scrollIntoView({ behavior: 'smooth', block: 'center' });

            // Apply Highlight
            element.style.transition = 'all 0.4s cubic-bezier(0.16, 1, 0.3, 1)';
            const originalBg = element.style.backgroundColor;
            const originalShadow = element.style.boxShadow;
            const originalBorder = element.style.border;

            element.style.backgroundColor = 'rgba(59, 130, 246, 0.2)'; 
            element.style.boxShadow = '0 0 20px rgba(59, 130, 246, 0.5)';
            element.style.border = '2px solid var(--primary)';

            console.log("[JumpEngine] Scroll and Highlight applied successfully.");
            console.groupEnd();

            setTimeout(() => {
                element.style.backgroundColor = originalBg;
                element.style.boxShadow = originalShadow;
                element.style.border = originalBorder;
            }, 3000);
        } else if (attempts < maxAttempts) {
            setTimeout(performScroll, 100);
        } else {
            console.warn("[JumpEngine] Failed to scroll: Element never became visible in layout.");
            console.groupEnd();
        }
    };

    // Initial delay to allow display:block to take effect
    setTimeout(performScroll, 300);
}

