1278 |         function aceFind(direction) {
1279 |             if (!aceEditorInstance) return;
1280 |             const input = document.getElementById('ace-search-input');
1281 |             const countEl = document.getElementById('ace-search-count');
1282 |             const query = input.value;
1283 |             
1284 |             if (!query) {
1285 |                 countEl.innerText = "";
1286 |                 aceEditorInstance.selection.clearSelection();
1287 |                 return;
1288 |             }
1289 | 
1290 |             // 1. Prepare Regex: Escape chars, then replace spaces with \s+
1291 |             // This allows "div> div" to match "div>\n\n   div"
1292 |             const escaped = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
1293 |             const pattern = escaped.replace(/\s+/g, '\\s+');
1294 |             
1295 |             // 2. Search Raw Content (Bypasses Ace's line-by-line limitation)
1296 |             const content = aceEditorInstance.getValue();
1297 |             const regex = new RegExp(pattern, 'gim'); // Global, Case-Insensitive, Multiline
1298 |             
1299 |             const matches = [];
1300 |             let match;
1301 |             // Find ALL matches in the entire file string
1302 |             while ((match = regex.exec(content)) !== null) {
1303 |                 matches.push({
1304 |                     index: match.index,
1305 |                     length: match[0].length
1306 |                 });
1307 |             }
1308 | 
1309 |             const total = matches.length;
1310 |             if (total === 0) {
1311 |                 countEl.innerText = "0 found";
1312 |                 return;
1313 |             }
1314 | 
1315 |             // 3. Find Current Position relative to matches
1316 |             const currentPos = aceEditorInstance.getCursorPosition();
1317 |             const currentIndexVal = aceEditorInstance.session.doc.positionToIndex(currentPos);
1318 |             
1319 |             // Find which match we are currently on or after
1320 |             let matchIdx = -1;
1321 |             for (let i = 0; i < total; i++) {
1322 |                 // Check if cursor is inside this match
1323 |                 if (currentIndexVal >= matches[i].index && currentIndexVal < matches[i].index + matches[i].length) {
1324 |                     matchIdx = i;
1325 |                     break;
1326 |                 }
1327 |             }
1328 | 
1329 |             // 4. Calculate Target Index
1330 |             let nextIdx = 0;
1331 |             if (direction === 'next') {
1332 |                 if (matchIdx !== -1) nextIdx = (matchIdx + 1) % total;
1333 |                 else {
1334 |                     // Find first match after cursor
1335 |                     nextIdx = matches.findIndex(m => m.index > currentIndexVal);
1336 |                     if (nextIdx === -1) nextIdx = 0; // Wrap to start
1337 |                 }
1338 |             } else if (direction === 'prev') {
1339 |                 if (matchIdx !== -1) nextIdx = (matchIdx - 1 + total) % total;
1340 |                 else {
1341 |                     // Find last match before cursor
1342 |                     for (let i = total - 1; i >= 0; i--) {
1343 |                         if (matches[i].index < currentIndexVal) {
1344 |                             nextIdx = i;
1345 |                             break;
1346 |                         }
1347 |                     }
1348 |                     if (nextIdx === -1) nextIdx = total - 1; // Wrap to end
1349 |                 }
1350 |             } else {
1351 |                 // Typing (No direction): Stay on current or find nearest
1352 |                 if (matchIdx !== -1) nextIdx = matchIdx;
1353 |                 else {
1354 |                     nextIdx = matches.findIndex(m => m.index >= currentIndexVal);
1355 |                     if (nextIdx === -1) nextIdx = 0;
1356 |                 }
1357 |             }
1358 | 
1359 |             // 5. Convert Index back to Ace Coordinates & Highlight
1360 |             const target = matches[nextIdx];
1361 |             const startPos = aceEditorInstance.session.doc.indexToPosition(target.index);
1362 |             const endPos = aceEditorInstance.session.doc.indexToPosition(target.index + target.length);
1363 |             
1364 |             const Range = ace.require('ace/range').Range;
1365 |             const aceRange = new Range(startPos.row, startPos.column, endPos.row, endPos.column);
1366 |             
1367 |             aceEditorInstance.selection.setRange(aceRange);
1368 |             aceEditorInstance.revealRange(aceRange);
1369 |             countEl.innerText = `${nextIdx + 1} of ${total}`;
1370 |         }
