 482 |         // Resolves relative paths (./utils.js) against a base (js/main.js) -> js/utils.js
 483 |         function resolvePath(base, relative) {
 484 |             const stack = base.split('/');
 485 |             stack.pop(); // Remove filename from base
 486 |             const parts = relative.split('/');
 487 |             for (let i = 0; i < parts.length; i++) {
 488 |                 if (parts[i] === '.') continue;
 489 |                 if (parts[i] === '..') stack.pop();
 490 |                 else stack.push(parts[i]);
 491 |             }
 492 |             return stack.join('/');
 493 |         }
