ng><span class="log-time">#${run.run_number}</span></div><div class="flex-gap"><small style="color:var(--text-muted)">${new Date(run.created_at).toLocaleTimeString()}</small>${isFail ? `<button class="btn-dev" style="padding:2px 8px; font-size:10px; width:auto;" onclick="triggerAutoFix('${run.id}')">Auto-Fix</button>` : ''}</div></div>`;\n                        container.appendChild(div);\n                    });\n                    document.getElementById('btn-load-workflows').style.display = data.runs.length >= 20 ? 'block' : 'none';\n                } else if (wPage === 1) {\n                    container.innerHTML = '<div style="padding:20px; text-align:center; color:#666;">No runs found.</div>';\n                }\n            } catch (e) { container.innerHTML = 'Error: ' + e.message; }\n        }\n        function loadMoreWorkflows() { wPage++; fetchWorkflows(); }\n\n        function jumpToHistory(conduitId) {\n            console.log(`[Jump] Target: ${conduitId}`);\n            switchTab('tab-history', document.querySelectorAll('.nav-item')[3]);\n            setTimeout(() => {\n                const targetId = `hist-item-${conduitId}`;\n                const element = document.getElementById(targetId);\n                if (element) {\n                    element.scrollIntoView({ behavior: 'smooth', block: 'center' });\n                    element.classList.remove('jump-highlight');\n                    void element.offsetWidth;\n                    element.classList.add('jump-highlight');\n                    console.log("[Jump] Success");\n                } else {\n                    console.error(`[Jump] Failed: ${targetId} not in DOM.`);\n                    alert("Item not found in current view. Load more history?");\n                }\n            }, 150);\n        }\n\n        async function triggerAutoFix(runId) {\n            if(!confirm("Trigger AI Auto-Fix?")) return;\n            const termId = addTerminalCard(null, { loading: true });\n        