1233 |         function aceFind(direction) {
1234 |             if (!aceEditorInstance) return;
1235 |             const input = document.getElementById('ace-search-input');
1236 |             const countEl = document.getElementById('ace-search-count');
1237 |             const query = input.value;
1238 |             
1239 |             if (!query) {
1240 |                 countEl.innerText = "";
1241 |                 aceEditorInstance.selection.clearSelection();
1242 |                 return;
1243 |             }
1244 | 
1245 |             // 1. Prepare Regex: Escape chars, then replace spaces with \s+
1246 |             // This allows "div> div" to match "div>\n\n   div"
1247 |             const escaped = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
1248 |             const pattern = escaped.replace(/\s+/g, '\\s+');
1249 |             
1250 |             // 2. Search Raw Content (Bypasses Ace's line-by-line limitation)
1251 |             const content = aceEditorInstance.getValue();
1252 |             const regex = new RegExp(pattern, 'gim'); // Global, Case-Insensitive, Multiline
1253 |             
1254 |             const matches = [];
1255 |             let match;
1256 |             // Find ALL matches in the entire file string
1257 |             while ((match = regex.exec(content)) !== null) {
1258 |                 matches.push({
1259 |                     index: match.index,
1260 |                     length: match[0].length
1261 |                 });
1262 |             }
1263 | 
1264 |             const total = matches.length;
1265 |             if (total === 0) {
1266 |                 countEl.innerText = "0 found";
1267 |                 return;
1268 |             }
1269 | 
1270 |             // 3. Find Current Position relative to matches
1271 |             const currentPos = aceEditorInstance.getCursorPosition();
1272 |             const currentIndexVal = aceEditorInstance.session.doc.positionToIndex(currentPos);
1273 |             
1274 |             // Find which match we are currently on or after
1275 |             let matchIdx = -1;
1276 |             for (let i = 0; i < total; i++) {
1277 |                 // Check if cursor is inside this match
1278 |                 if (currentIndexVal >= matches[i].index && currentIndexVal < matches[i].index + matches[i].length) {
1279 |                     matchIdx = i;
1280 |                     break;
1281 |                 }
1282 |             }
1283 | 
1284 |             // 4. Calculate Target Index
1285 |             let nextIdx = 0;
1286 |             if (direction === 'next') {
1287 |                 if (matchIdx !== -1) nextIdx = (matchIdx + 1) % total;
1288 |                 else {
1289 |                     // Find first match after cursor
1290 |                     nextIdx = matches.findIndex(m => m.index > currentIndexVal);
1291 |                     if (nextIdx === -1) nextIdx = 0; // Wrap to start
1292 |                 }
1293 |             } else if (direction === 'prev') {
1294 |                 if (matchIdx !== -1) nextIdx = (matchIdx - 1 + total) % total;
1295 |                 else {
1296 |                     // Find last match before cursor
1297 |                     for (let i = total - 1; i >= 0; i--) {
1298 |                         if (matches[i].index < currentIndexVal) {
1299 |                             nextIdx = i;
1300 |                             break;
1301 |                         }
1302 |                     }
1303 |                     if (nextIdx === -1) nextIdx = total - 1; // Wrap to end
1304 |                 }
1305 |             } else {
1306 |                 // Typing (No direction): Stay on current or find nearest
1307 |                 if (matchIdx !== -1) nextIdx = matchIdx;
1308 |                 else {
1309 |                     nextIdx = matches.findIndex(m => m.index >= currentIndexVal);
1310 |                     if (nextIdx === -1) nextIdx = 0;
1311 |                 }
1312 |             }
1313 | 
1314 |             // 5. Convert Index back to Ace Coordinates & Highlight
1315 |             const target = matches[nextIdx];
1316 |             const startPos = aceEditorInstance.session.doc.indexToPosition(target.index);
1317 |             const endPos = aceEditorInstance.session.doc.indexToPosition(target.index + target.length);
1318 |             
1319 |             const Range = ace.require('ace/range').Range;
1320 |             const aceRange = new Range(startPos.row, startPos.column, endPos.row, endPos.column);
1321 |             
1322 |             aceEditorInstance.selection.setRange(aceRange);
1323 |             aceEditorInstance.revealRange(aceRange);
1324 |             countEl.innerText = `${nextIdx + 1} of ${total}`;
1325 |         }
