// --- API & DATA FETCHING ---
function resetOffsets() { hOffset = 0; lOffset = 0; }

async function fetchState(force = false) {
    const histContainer = document.getElementById('history-container');
    const termContainer = document.getElementById('terminal-list');
    if(force) {
        resetOffsets();
        histContainer.innerHTML = '<div style="padding:10px; text-align:center;">Syncing...</div>';
        termContainer.innerHTML = '<div style="padding:10px; text-align:center; color:#666">Syncing logs...</div>';
    }
    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'init', history_offset: hOffset, log_offset: lOffset })
        });
        const data = await res.json();
        if (hOffset === 0) histContainer.innerHTML = '';
        if (lOffset === 0) termContainer.innerHTML = '';

        if (data.history && data.history.length > 0) {
            dbHistory = hOffset === 0 ? data.history : [...dbHistory, ...data.history];
            renderHistory(data.history, hOffset > 0);
            document.getElementById('btn-load-history').style.display = data.history.length >= PAGE_SIZE ? 'block' : 'none';
        } else if (hOffset === 0) {
            histContainer.innerHTML = '<div style="padding:10px; text-align:center;">No history found.</div>';
        }

        if (data.logs && data.logs.length > 0) {
            data.logs.forEach(log => {
                const id = 'term-saved-' + log.id;
                const div = document.createElement('div');
                div.id = id; div.className = 'log-entry'; div.style.marginBottom = '12px';
                termContainer.appendChild(div);
                updateTerminalCard(id, log.data, null);
                const timeEl = div.querySelector('.log-time');
                if(timeEl) timeEl.innerText = new Date(log.created_at).toLocaleString();
            });
            document.getElementById('btn-load-logs').style.display = data.logs.length >= PAGE_SIZE ? 'block' : 'none';
        } else if (lOffset === 0) {
            termContainer.innerHTML = '<div style="padding:10px; text-align:center; color:#444;">No logs found.</div>';
        }
    } catch (e) { console.error(e); }
}

function loadMoreHistory() { hOffset += PAGE_SIZE; fetchState(); }
function loadMoreLogs() { lOffset += PAGE_SIZE; fetchState(); }

async function fetchWorkflows() {
    const container = document.getElementById('workflow-list');
    if (wPage === 1) container.innerHTML = '<div style="padding:20px; text-align:center;">Fetching Runs...</div>';
    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'fetch_workflows', page: wPage })
        });
        const data = await res.json();
        if (wPage === 1) container.innerHTML = '';
        if (data.runs && data.runs.length > 0) {
            data.runs.forEach(run => {
                const div = document.createElement('div');
                div.className = 'log-entry'; div.style.marginBottom = '10px';
                const isFail = run.conclusion === 'failure';
                div.innerHTML = `<div class="log-header"><div class="log-meta"><span class="status-pill ${isFail ? 'pill-fail' : 'pill-success'}">${run.conclusion || 'running'}</span><strong>${run.name}</strong><span class="log-time">#${run.run_number}</span></div><div class="flex-gap"><small style="color:var(--text-muted)">${new Date(run.created_at).toLocaleTimeString()}</small>${isFail ? `<button class="btn-dev" style="padding:2px 8px; font-size:10px; width:auto;" onclick="triggerAutoFix('${run.id}')">Auto-Fix</button>` : ''}</div></div>`;
                container.appendChild(div);
            });
            document.getElementById('btn-load-workflows').style.display = data.runs.length >= 20 ? 'block' : 'none';
        } else if (wPage === 1) {
            container.innerHTML = '<div style="padding:20px; text-align:center; color:#666;">No runs found.</div>';
        }
    } catch (e) { container.innerHTML = 'Error: ' + e.message; }
}
function loadMoreWorkflows() { wPage++; fetchWorkflows(); }

