        .scope-overlay { position: absolute; top:0; left:0; width:100%; height:100%; backdrop-filter: invert(1) hue-rotate(180deg) brightness(1.5); opacity: 0.4; }
        @keyframes scope-intro { from { width: 0; height: 0; opacity: 0; } to { width: 250px; height: 250px; opacity: 1; } }

        /* Scanline */
