        @keyframes scan { from { top: 0; } to { top: 100%; } }

        /* Branching UI */
        #choice-overlay { position: absolute; top: 0; left: 0; width: 100%; height: 100%; display: none; flex-direction: column; align-items: center; justify-content: center; background: rgba(0,0,0,0.6); backdrop-filter: blur(5px); z-index: 600; pointer-events: auto; }
