function renderHistory(historyData) {
     const container = document.getElementById('history-container');
     if(!historyData || historyData.length === 0) return container.innerHTML = '<div style="padding:10px; text-align:center;">No history.</div>';
     container.innerHTML = historyData.filter(h => h.title !== "Rollback").map((h, index) => {
         const canLoad = !!h.ops;
