         const canLoad = !!h.ops; const canRestore = !!h.sha; 
         return `<div class="version-item" id="hist-item-${h.conduit_id}"><div class="v-header"><div class="v-info"><strong>${h.title}</strong><small>${new Date(h.created_at).toLocaleString()}</small></div><div style="position:relative"><button class="menu-btn" onclick="event.stopPropagation(); toggleMenu(${globalIdx})">⋮</button><div id="menu-${globalIdx}" class="menu-dropdown">${canLoad ? `<div class="menu-item" onclick="loadVersion(${globalIdx})">Load Patch</div>` : ''}<div class="menu-item" onclick="bundleAndPreview(${globalIdx})">Preview</div><div class="menu-item" onclick="addNote(${globalIdx})">Note</div><div class="menu-item danger" onclick="deleteHistory(${globalIdx})">Delete</div>${canRestore ? `<div class="menu-item danger" onclick="handleRestore(${globalIdx})">Restore State</div>` : ''}</div></div></div><div class="v-note ${h.note ? 'has-content' : ''}" onclick="addNote(${globalIdx})">${h.note || ''}</div></div>`;
    }).join('');
    if (append) container.insertAdjacentHTML('beforeend', html);
    else container.innerHTML = html;
}

