 682 |         // --- THE MODULE BUNDLER (Recursive) ---
 683 |         // --- THE MODULE BUNDLER (With Multiline Import Support) ---
 684 |   async function bundleAndPreview(index) {
 685 |             if(!CONFIG.funcUrl) return;
 686 | 
 687 |             // 1. Setup Context
 688 |             let entry = (typeof index === 'number') ? dbHistory[index] : null;
 689 |             let sha = entry ? entry.sha : null;
 690 |             let rootPrefix = ''; 
 691 |             if (entry && entry.type === 'Prod') {
 692 |                 const match = entry.title.match(/Deployed\s+(.+)/);
 693 |                 if (match && match[1]) rootPrefix = `${match[1]}/`;
 694 |             }
 695 |             
 696 |             // FIX: We use effectiveRoot for stripping paths to ensure subfolders (DSE/) are flattened
 697 |             const effectiveRoot = rootPrefix || CONFIG.projectPath;
 698 |             const entryFile = effectiveRoot + 'index.html';
 699 |             const iframe = document.getElementById('preview-frame');
 700 |             iframe.srcdoc = `<div style="color:#666; font-family:sans-serif; text-align:center; padding:20px;">Bundling ${entryFile}...</div>`;
 701 | 
 702 |             // 2. Fetch All Files
 703 |             let allFiles = [];
 704 |             try {
 705 |                  const res = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'fetch' }) });
 706 |                  const data = await res.json();
 707 |                  allFiles = data.files.map(f => f.path);
 708 |             } catch(e) { return iframe.srcdoc = "Error fetching file list"; }
 709 | 
 710 |             const fileCache = {}; 
 711 |             const versionFiles = allFiles.filter(f => f.startsWith(effectiveRoot));
 712 | 
 713 |             async function fetchAndCache(path) {
 714 |                 if(fileCache[path]) return;
 715 |                 try {
 716 |                     const res = await fetch(CONFIG.funcUrl, {
 717 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
 718 |                         body: apiBody({ action: 'preview_file', file_path: path, ref_sha: sha })
 719 |                     });
 720 |                     const data = await res.json();
 721 |                     if(data.content) fileCache[path] = { content: b64DecodeUnicode(data.content), mime: getMime(path) };
 722 |                 } catch(e) {}
 723 |             }
 724 |             function getMime(path) {
 725 |                 if(path.endsWith('.html')) return 'text/html';
 726 |                 if(path.endsWith('.js')) return 'text/javascript';
 727 |                 if(path.endsWith('.css')) return 'text/css';
 728 |                 return 'application/octet-stream';
 729 |             }
 730 | 
 731 |             await Promise.all(versionFiles.map(f => fetchAndCache(f)));
 732 |             if(!fileCache[entryFile]) return iframe.srcdoc = `Error: ${entryFile} not found`;
 733 | 
 734 |             // 3. REWRITE IMPORTS (The Linker)
 735 |             function rewriteImports(code, currentPath) {
 736 |                 return code.replace(/(import|export)([\s\S]*?)(['"])([^'"]+)(['"])/g, (match, keyword, mid, q1, importPath, q2) => {
 737 |                     if(importPath.startsWith('.')) {
 738 |                         const resolved = resolvePath(currentPath, importPath);
 739 |                         
 740 |                         // FIX: Use effectiveRoot to strip the prefix (e.g. "DSE/ui.js" -> "ui.js")
 741 |                         const cleanKey = resolved.startsWith(effectiveRoot) ? resolved.substring(effectiveRoot.length) : resolved;
 742 |                         return `${keyword}${mid}${q1}${cleanKey}${q2}`;
 743 |                     }
 744 |                     return match;
 745 |                 });
 746 |             }
 747 | 
 748 |             // Rewrite all cached JS files
 749 |             Object.keys(fileCache).forEach(path => {
 750 |                 if(fileCache[path].mime === 'text/javascript') {
 751 |                     fileCache[path].content = rewriteImports(fileCache[path].content, path);
 752 |                 }
 753 |             });
 754 | 
 755 |             // 4. GENERATE BLOBS & IMPORT MAP
 756 |             const importMap = { imports: {} };
 757 |             Object.keys(fileCache).forEach(path => {
 758 |                 // FIX: Use effectiveRoot to generate flat map keys
 759 |                 const mapKey = path.startsWith(effectiveRoot) ? path.substring(effectiveRoot.length) : path;
 760 |                 const blob = new Blob([fileCache[path].content], { type: fileCache[path].mime });
 761 |                 const blobUrl = URL.createObjectURL(blob);
 762 |                 fileCache[path].blobUrl = blobUrl;
 763 |                 importMap.imports[mapKey] = blobUrl;
 764 |             });
 765 | 
 766 |             // 5. INJECT INTO HTML
 767 |             let html = fileCache[entryFile].content;
 768 |             const parser = new DOMParser();
 769 |             const doc = parser.parseFromString(html, 'text/html');
 770 | 
 771 |             // Fix A: Rewrite Inline Scripts
 772 |             doc.querySelectorAll('script:not([src])').forEach(el => {
 773 |                 if (el.type === 'module' || el.textContent.includes('import')) {
 774 |                     el.textContent = rewriteImports(el.textContent, entryFile);
 775 |                 }
 776 |             });
 777 | 
 778 |             // Fix B: Rewrite External Scripts
 779 |             doc.querySelectorAll('script[src]').forEach(el => {
