1221 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1222 |     function applyLocalPatch(content, ops) {
1223 |         let lines = content.split('\n');
1224 |         let logs = [];
1225 |         let success = true;
1226 | 
1227 |         if (typeof ops === 'string') {
1228 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1229 |         }
1230 | 
1231 |         ops.forEach(op => {
1232 |             if (op.action === 'comment') return;
1233 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1234 |             
1235 |             if (op.action === 'replace_block') {
1236 |                 // Strategy 1: Exact String Match (Fastest)
1237 |                 const currentStr = lines.join('\n');
1238 |                 if (currentStr.includes(op.find_block)) {
1239 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1240 |                     logs.push('Exact match applied');
1241 |                     return;
1242 |                 }
1243 | 
1244 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1245 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1246 |                 if (searchLines.length === 0) return;
1247 | 
1248 |                 let matchStart = -1;
1249 |                 let matchEnd = -1;
1250 | 
1251 |                 // Scan file lines
1252 |                 for (let i = 0; i < lines.length; i++) {
1253 |                     // If first line matches (ignoring whitespace)
1254 |                     if (lines[i].trim() === searchLines[0]) {
1255 |                         // Check subsequent lines
1256 |                         let allMatch = true;
1257 |                         let fileOffset = 0;
1258 |                         let searchOffset = 1;
1259 |                         
1260 |                         while (searchOffset < searchLines.length) {
1261 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1262 |                             const nextFile = lines[i + fileOffset + 1].trim();
1263 |                             // Skip empty lines in file if they aren't in search block
1264 |                             if (nextFile === '') {
1265 |                                 fileOffset++;
1266 |                                 continue;
1267 |                             }
1268 |                             if (nextFile !== searchLines[searchOffset]) {
1269 |                                 allMatch = false;
1270 |                                 break;
1271 |                             }
1272 |                             fileOffset++;
1273 |                             searchOffset++;
1274 |                         }
1275 | 
1276 |                         if (allMatch) {
1277 |                             matchStart = i;
1278 |                             matchEnd = i + fileOffset;
1279 |                             break;
1280 |                         }
1281 |                     }
1282 |                 }
1283 | 
1284 |                 if (matchStart !== -1) {
1285 |                     // Replace the range of lines
1286 |                     const replacement = op.replace_with.split('\n');
1287 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1288 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1289 |                 } else {
1290 |                     success = false;
1291 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1292 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1293 |                 }
1294 |             }
1295 |         });
1296 |         return { content: lines.join('\n'), success, logs };
1297 |     }
