3225 |     function formatBytes(bytes) {
3226 |         if (!bytes) return '0 B';
3227 |         const k = 1024;
3228 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3229 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3230 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
3231 |     }
