3233 |     function timeAgo(dateString) {
3234 |         const date = new Date(dateString);
3235 |         const now = new Date();
3236 |         const seconds = Math.floor((now - date) / 1000);
3237 |         if (seconds < 10) return 'just now';
3238 |         if (seconds < 60) return seconds + 's ago';
3239 |         const minutes = Math.floor(seconds / 60);
3240 |         if (minutes < 60) return minutes + 'm ago';
3241 |         const hours = Math.floor(minutes / 60);
3242 |         if (hours < 24) return hours + 'h ago';
3243 |         return date.toLocaleDateString();
3244 |     }
