3355 |     function jumpToElement(element, tabId, navIndex) {
3356 |         console.group(`[JumpEngine] Triggered: ${tabId}`);
3357 |         if (!element) {
3358 |             console.error("[JumpEngine] Failed: Element is null");
3359 |             console.groupEnd();
3360 |             return;
3361 |         }
3362 | 
3363 |         // 1. Force Tab Switch
3364 |         const navItems = document.querySelectorAll('.nav-item');
3365 |         switchTab(tabId, navItems[navIndex]);
3366 |         console.log("[JumpEngine] Tab switched.");
3367 | 
3368 |         const scrollContainer = document.querySelector('.main-view');
3369 |         
3370 |         let attempts = 0;
3371 |         const scrollLogic = () => {
3372 |             attempts++;
3373 |             
3374 |             // Calculate position relative to the scroll container
3375 |             // We iterate up the offsetParents until we hit the container
3376 |             let offsetTop = 0;
3377 |             let curr = element;
3378 |             while (curr && curr !== scrollContainer) {
3379 |                 offsetTop += curr.offsetTop;
3380 |                 curr = curr.offsetParent;
3381 |             }
3382 | 
3383 |             console.log(`[JumpEngine] Attempt ${attempts}: Calculated offsetTop as ${offsetTop}`);
3384 | 
3385 |             if (offsetTop > 0 || attempts > 3) {
3386 |                 // Center the element: targetTop = offsetTop - (containerHeight / 2) + (elementHeight / 2)
3387 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
3388 |                 
3389 |                 console.log(`[JumpEngine] Executing scroll to: ${targetScroll}`);
3390 |                 
3391 |                 scrollContainer.scrollTo({
3392 |                     top: targetScroll,
3393 |                     behavior: 'smooth'
3394 |                 });
3395 | 
3396 |                 // Visual Feedback
3397 |                 element.style.transition = 'all 0.5s ease';
3398 |                 const oldBg = element.style.backgroundColor;
3399 |                 const oldShadow = element.style.boxShadow;
3400 |                 const oldBorder = element.style.border;
3401 | 
3402 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
3403 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
3404 |                 element.style.border = '2px solid var(--primary)';
3405 | 
3406 |                 setTimeout(() => {
3407 |                     element.style.backgroundColor = oldBg;
3408 |                     element.style.boxShadow = oldShadow;
3409 |                     element.style.border = oldBorder;
3410 |                 }, 3000);
3411 | 
3412 |                 console.groupEnd();
3413 |             } else {
3414 |                 // If offset is still 0, the tab content might still be hidden/rendering
3415 |                 setTimeout(scrollLogic, 150);
3416 |             }
3417 |         };
3418 | 
3419 |         // Wait for tab transition animation before starting logic
3420 |         setTimeout(scrollLogic, 250);
3421 |     }
